/*
 * Normalize a Meta (Facebook/Instagram) Lead Ads lead into the cliniqboost shape:
 *   { clinic_id, source, name, phone, email, treatment_interest }
 *
 * Meta delivers answers as a field_data array: [{ name, values: [..] }].
 * Some n8n versions / manual test payloads flatten these to top-level keys,
 * so we read both. Custom "treatment" questions vary in field name, hence the
 * generous key list below.
 */
const out = [];
for (const entry of $input.all()) {
  const item = entry.json || {};

  const fd = item.field_data || item.fieldData;
  const fromFieldData = (keys) => {
    if (!Array.isArray(fd)) return undefined;
    for (const f of fd) {
      const nm = String(f.name || '').toLowerCase();
      if (keys.includes(nm)) {
        const v = Array.isArray(f.values) ? f.values[0] : f.value;
        if (v) return v;
      }
    }
    return undefined;
  };

  const name = item.full_name || item.name
    || fromFieldData(['full_name', 'name', 'your_name'])
    || [item.first_name, item.last_name].filter(Boolean).join(' ').trim()
    || null;
  const phone = item.phone_number || item.phone
    || fromFieldData(['phone_number', 'phone', 'mobile', 'mobile_number']) || null;
  const email = item.email
    || fromFieldData(['email', 'email_address']) || null;
  const treatment_interest = item.treatment_interest || item.treatment
    || fromFieldData(['treatment_interest', 'treatment', 'service', 'interest',
        'what_service_are_you_interested_in', 'which_treatment']) || null;

  out.push({
    json: {
      // ▼▼ Fill in per-client at onboarding ▼▼
      clinic_id: 'REPLACE_WITH_CLINIC_UUID',
      source: 'ad_form',
      name,
      phone,
      email,
      treatment_interest
    }
  });
}
return out;

/*
 * Normalize a Google Ads Lead Form Extension lead into the cliniqboost shape.
 * Google POSTs JSON to a webhook; the n8n Webhook node nests it under $json.body.
 * Fields arrive in user_column_data: [{ column_id, string_value }], where
 * column_id is an enum like FULL_NAME / PHONE_NUMBER / EMAIL (custom questions
 * use the question text). We read column_id and column_name defensively.
 */
const out = [];
for (const entry of $input.all()) {
  const body = (entry.json && entry.json.body) || entry.json || {};

  const cols = body.user_column_data || body.userColumnData;
  const fromColumns = (ids) => {
    if (!Array.isArray(cols)) return undefined;
    const wanted = ids.map((s) => s.toUpperCase());
    for (const c of cols) {
      const id = String(c.column_id || c.columnId || '').toUpperCase();
      const nm = String(c.column_name || c.columnName || '').toUpperCase();
      if (wanted.includes(id) || wanted.includes(nm)) {
        const v = c.string_value || c.stringValue;
        if (v) return v;
      }
    }
    return undefined;
  };

  const name = fromColumns(['FULL_NAME', 'NAME', 'FIRST_NAME']) || body.full_name || body.name || null;
  const phone = fromColumns(['PHONE_NUMBER', 'PHONE']) || body.phone_number || body.phone || null;
  const email = fromColumns(['EMAIL', 'USER_EMAIL']) || body.email || null;
  const treatment_interest = fromColumns(['TREATMENT_INTEREST', 'SERVICE', 'INTEREST', 'TREATMENT'])
    || body.treatment_interest || null;

  out.push({
    json: {
      // ▼▼ Fill in per-client at onboarding ▼▼
      clinic_id: 'REPLACE_WITH_CLINIC_UUID',
      source: 'ad_form',
      name,
      phone,
      email,
      treatment_interest
    }
  });
}
return out;
